import{_ as a,o as t,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"63. Casual Employment Caring Responsibilities","description":"","frontmatter":{"title":"63. Casual Employment Caring Responsibilities","eba":"Allied Health Professionals 2021-2026","topics":["leave","personal-leave","employment","preliminary"]},"headers":[],"relativePath":"ebas/allied-health/leave/63-casual-employment-caring-responsibilities.md","filePath":"ebas/allied-health/leave/63-casual-employment-caring-responsibilities.md"}'),l={name:"ebas/allied-health/leave/63-casual-employment-caring-responsibilities.md"};function s(i,e,r,p,m,c){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_63-casual-employment-caring-responsibilities" tabindex="-1">63. Casual Employment Caring Responsibilities <a class="header-anchor" href="#_63-casual-employment-caring-responsibilities" aria-label="Permalink to &quot;63. Casual Employment Caring Responsibilities&quot;">​</a></h1><p><strong>63.1</strong> Subject to the evidence and notice requirements that apply to carer’s leave under <a href="/eba/ebas/allied-health/leave/62-personal-leave-including-carer-s-leave.html">clause 62</a>, a casual Employee is entitled to be unavailable to attend work, or to leave work, if they need to provide care or support to a member of the Employee’s Immediate Family or household because of:</p><p><strong>(a)</strong> a personal illness, or personal injury, affecting them;</p><p><strong>(b)</strong> an unexpected emergency affecting them; or</p><p><strong>(c)</strong> the birth of a child.</p><p><strong>63.2</strong> The Employer and the Employee will agree on the period for which the Employee will be entitled to be unavailable to attend work. In the absence of agreement, the Employee is entitled to be unavailable to attend work for up to three (3) days per occasion, which may be taken as a single continuous period of up to three (3) days or any separate periods to which the Employer and Employee agree.</p><p><strong>63.3</strong> A casual Employee is not entitled to any payment for the period of non- attendance.</p><p><strong>63.4</strong> An Employer must not fail to re-engage a casual Employee because the Employee accessed the entitlements provided for in this clause 63. The rights of the Employer to engage or not to engage a casual Employee are otherwise not affected.</p><p>Plain language terms: casual.</p>',9)])])}const u=a(l,[["render",s]]);export{d as __pageData,u as default};
